	private static ArbitraryLengthPath findArbitraryLengthPath(TupleExpr tupleExpr) {
		AtomicReference<ArbitraryLengthPath> result = new AtomicReference<>();
		tupleExpr.visit(new AbstractSimpleQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(ArbitraryLengthPath node) {
				result.compareAndSet(null, node);
			}
		});
		return result.get();
	}

	private static List<ArbitraryLengthPath> findArbitraryLengthPaths(TupleExpr tupleExpr) {
		List<ArbitraryLengthPath> result = new ArrayList<>();
		tupleExpr.visit(new AbstractSimpleQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(ArbitraryLengthPath node) {
				result.add(node);
			}
		});
		return result;
	}

	private static double propertyPathWork(JoinFactorCostModel costModel, ArbitraryLengthPath path,
			Set<String> boundVars) {
		Optional<JoinFactorCostModel.FactorCostEstimate> estimate = costModel.estimateFactorCost(path,
				JoinFactorCostModel.CostContext.of(boundVars, 1.0d, 1.0d, false));
		assertTrue(estimate.isPresent());
		return estimate.get().getWorkRows();
	}

	private static void assertPropertyPathCosted(ArbitraryLengthPath path, Explanation explanation) {
		String method = path.getStringMetricPlanned("plannedPropertyPathMethod");
		String source = path.getStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE);
		String proof = path.getStringMetricPlanned("optimizer.cascadesProofs");
		assertTrue((method != null && method.startsWith("sketch-single-predicate-path"))
				|| "lmdb-property-path".equals(source)
				|| (proof != null && proof.contains("lmdb-property-path")), explanation::toString);
		assertTrue(path.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS) > 1.0d,
				explanation::toString);
		assertTrue(path.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_WORK_ROWS) > 1.0d,
				explanation::toString);
	}

	private static void assertNoUnanchoredRelationshipTypeDirectLookup(TupleExpr tupleExpr, Explanation explanation) {
		List<StatementPattern> badPatterns = new ArrayList<>();
		tupleExpr.visit(new AbstractSimpleQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(StatementPattern node) {
				if (isRelationshipElementTypePattern(node)
						&& isSubjectObjectDirectLookup(node)
						&& !isBoundByLeftAncestor(node, "rel")) {
					badPatterns.add(node);
				}
			}
		});
		assertTrue(badPatterns.isEmpty(), () -> explanation.toString());
	}

	private static void assertNoPositiveCartesianJoinWork(TupleExpr tupleExpr, Explanation explanation) {
		List<Join> badJoins = new ArrayList<>();
		tupleExpr.visit(new AbstractSimpleQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Join node) {
				double cartesianWork = node
						.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_COST_CARTESIAN_WORK_ROWS);
				if (Double.isFinite(cartesianWork) && cartesianWork > 0.0d) {
					badJoins.add(node);
				}
				super.meet(node);
			}
		});
		assertTrue(badJoins.isEmpty(), () -> explanation.toString());
	}

	private static boolean isRelationshipElementTypePattern(StatementPattern pattern) {
		return pattern.getSubjectVar() != null
				&& "rel".equals(pattern.getSubjectVar().getName())
				&& pattern.getPredicateVar() != null
				&& RDF.TYPE.equals(pattern.getPredicateVar().getValue())
				&& pattern.getObjectVar() != null
				&& AAS_RELATIONSHIP_ELEMENT.equals(pattern.getObjectVar().getValue());
	}

	private static boolean isSubjectObjectDirectLookup(StatementPattern pattern) {
		return "directLookup".equals(pattern.getStringMetricPlanned(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE))
				&& "[S, P, O]".equals(pattern.getStringMetricPlanned(TelemetryMetricNames.PLANNED_LOOKUP_COMPONENTS));
	}

	private static boolean isBoundByLeftAncestor(QueryModelNode node, String bindingName) {
		QueryModelNode current = node;
		QueryModelNode parent = current.getParentNode();
		while (parent != null) {
			if (parent instanceof Join join && containsNode(join.getRightArg(), current)
					&& join.getLeftArg().getBindingNames().contains(bindingName)) {
				return true;
			}
			current = parent;
			parent = parent.getParentNode();
		}
		return false;
	}

	private static boolean containsNode(QueryModelNode root, QueryModelNode needle) {
		if (root == needle) {
			return true;
		}
		AtomicReference<Boolean> found = new AtomicReference<>(false);
		root.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meetNode(QueryModelNode node) {
				if (node == needle) {
					found.set(true);
				}
				if (!found.get()) {
					super.meetNode(node);
				}
			}
		});
		return found.get();
	}

	private static void loadAasDriveAggregationData(SailRepositoryConnection connection) {
		loadAasDriveAggregationData(connection, 12, 3, 4);
	}

	private static void loadAasDriveAggregationData(SailRepositoryConnection connection, int lineCount,
			int drivesPerLine, int noisePropertiesPerComponent) {
		for (int lineIndex = 0; lineIndex < lineCount; lineIndex++) {
			IRI line = VF.createIRI("urn:aas:line:", Integer.toString(lineIndex));
			IRI lineSubmodel = VF.createIRI("urn:aas:line-submodel:", Integer.toString(lineIndex));
			connection.add(line, RDF.TYPE, AAS_ASSET_ADMINISTRATION_SHELL);
			connection.add(line, AAS_SUBMODEL, lineSubmodel);
			for (int driveIndex = 0; driveIndex < drivesPerLine; driveIndex++) {
				int componentIndex = lineIndex * 10 + driveIndex;
				IRI rel = VF.createIRI("urn:aas:rel:", lineIndex + "-" + driveIndex);
				IRI ref = VF.createIRI("urn:aas:ref:", lineIndex + "-" + driveIndex);
				IRI component = VF.createIRI("urn:aas:component:", Integer.toString(componentIndex));
				connection.add(lineSubmodel, AAS_SUBMODEL_ELEMENT, rel);
				connection.add(rel, RDF.TYPE, AAS_RELATIONSHIP_ELEMENT);
				connection.add(rel, AAS_SECOND, ref);
				connection.add(ref, AAS_EXT_RESOLVES_TO, component);
				addComponentWithRatedPower(connection, component, componentIndex, noisePropertiesPerComponent);
			}
		}
	}

	private static void loadAasAssetInfoData(SailRepositoryConnection connection) {
		IRI assetInformation = VF.createIRI(AAS_NS, "assetInformation");
		IRI specificAssetId = VF.createIRI(AAS_NS, "specificAssetId");
		for (int componentIndex = 0; componentIndex < 36; componentIndex++) {
			IRI component = VF.createIRI("urn:aas:component:", Integer.toString(componentIndex));
			IRI info = VF.createIRI("urn:aas:asset-info:", Integer.toString(componentIndex));
			IRI id = VF.createIRI("urn:aas:specific-asset-id:", Integer.toString(componentIndex));
			connection.add(component, assetInformation, info);
			connection.add(info, specificAssetId, id);
			connection.add(id, AAS_VALUE, VF.createLiteral(componentIndex % 3 == 0 ? "DriveUnit" : "OtherUnit"));
		}
	}

	private static void addComponentWithRatedPower(SailRepositoryConnection connection, IRI component,
			int componentIndex) {
		addComponentWithRatedPower(connection, component, componentIndex, 4);
	}

	private static void addComponentWithRatedPower(SailRepositoryConnection connection, IRI component,
			int componentIndex, int noiseProperties) {
		IRI submodel = VF.createIRI("urn:aas:component-submodel:", Integer.toString(componentIndex));
		IRI root = VF.createIRI("urn:aas:component-root:", Integer.toString(componentIndex));
		IRI folder = VF.createIRI("urn:aas:component-folder:", Integer.toString(componentIndex));
		IRI ratedPower = VF.createIRI("urn:aas:rated-power:", Integer.toString(componentIndex));
		connection.add(component, RDF.TYPE, AAS_ASSET_ADMINISTRATION_SHELL);
		connection.add(component, AAS_SUBMODEL, submodel);
		connection.add(submodel, AAS_SUBMODEL_ELEMENT, root);
		connection.add(root, AAS_VALUE, folder);
		connection.add(folder, AAS_VALUE, ratedPower);
		connection.add(ratedPower, AAS_ID_SHORT, VF.createLiteral("ratedPower"));
		connection.add(ratedPower, AAS_VALUE, VF.createLiteral(10.0d + componentIndex));
		for (int noiseIndex = 0; noiseIndex < noiseProperties; noiseIndex++) {
			IRI noise = VF.createIRI("urn:aas:noise-property:", componentIndex + "-" + noiseIndex);
			connection.add(root, AAS_VALUE, noise);
			connection.add(noise, AAS_ID_SHORT, VF.createLiteral("temperature" + noiseIndex));
			connection.add(noise, AAS_VALUE, VF.createLiteral(componentIndex + noiseIndex));
		}
	}
